document.addEventListener("DOMContentLoaded",()=>{const e=document.querySelector(".site-header");if(!e)return;const r=document.querySelector("#toolbar"),n=document.querySelector("#toolbar-item-administration-tray"),i=document.querySelector(".gin-secondary-toolbar--frontend");function t(){e.classList.toggle("scrolled",window.scrollY>40);let o=0;if(r&&(o+=r.offsetHeight),n&&n.classList.contains("is-active")&&(o+=n.offsetHeight),i){const a=i.getBoundingClientRect().bottom;e.style.insetBlockStart=`${Math.max(o,a)}px`}else e.style.insetBlockStart=`${o}px`}t(),window.addEventListener("scroll",t,{passive:!0}),window.addEventListener("resize",t,{passive:!0}),document.addEventListener("drupalToolbarTrayChange",t)});
